AdditionConfig = {}
AdditionConfig.Config = {}

function AdditionConfig:init(config)
    for _,vConfig in pairs(config) do
        local data = {}
        data.Id = tonumber(vConfig.Id)
        data.propertyName = vConfig.propertyName
        data.toneUp = tonumber(vConfig.toneUp)
        self.Config[data.Id] = data
    end
end

function AdditionConfig:getConfigById(id)
    return self.Config[id]
end

